def _parse_command_parts(command_string):
    """Parse command string into parts, respecting quoted strings."""
    parts = []
    current = []
    in_quotes = False
    quote_char = None
    escape_next = False

    for char in command_string:
        if escape_next:
            current.append(char)
            escape_next = False
            continue

        if char == '\\' and in_quotes:
            escape_next = True
            continue

        if char in ('"', "'") and not in_quotes:
            in_quotes = True
            quote_char = char
            continue

        if char == quote_char and in_quotes:
            in_quotes = False
            quote_char = None
            continue

        if char == ' ' and not in_quotes:
            if current:
                parts.append(''.join(current))
                current = []
            continue

        current.append(char)

    if in_quotes:
        raise ValueError("Unterminated quoted string in command")

    if current:
        parts.append(''.join(current))

    return parts


